    public Object parseDepositWithdrawFee(Object fee, Object... optionalArgs)
    {
        //
        //    {
        //        "currency": "USDT",
        //        "limitBTCAmount": "1.00000000",
        //        "usedBTCAmount": "0.00000000",
        //        "remainAmount": "16548.072149",
        //        "availableAmount": "0",
        //        "withdrawMinFee": "25",
        //        "innerWithdrawMinFee": "0",
        //        "withdrawMinSize": "50",
        //        "isWithdrawEnabled": true,
        //        "precision": 6,
        //        "chain": "ERC20"
        //    }
        //
        // if data obtained through `currencies` endpoint
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        if (Helpers.isTrue(Helpers.inOp(fee, "chains")))
        {
            Object resultNew = new java.util.HashMap<String, Object>() {{
                put( "info", fee );
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "fee", null );
                    put( "percentage", false );
                }} );
                put( "deposit", new java.util.HashMap<String, Object>() {{
                    put( "fee", null );
                    put( "percentage", null );
                }} );
                put( "networks", new java.util.HashMap<String, Object>() {{}} );
            }};
            Object chains = this.safeList(fee, "chains", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(chains)); i++)
            {
                Object chain = Helpers.GetValue(chains, i);
                Object networkCodeNew = this.networkIdToCode(this.safeString(chain, "chainId"), this.safeString(currency, "code"));
                Helpers.addElementToObject(Helpers.GetValue(resultNew, "networks"), networkCodeNew, new java.util.HashMap<String, Object>() {{
    put( "withdraw", new java.util.HashMap<String, Object>() {{
        put( "fee", Kucoin.this.safeNumber2(chain, "withdrawalMinFee", "withdrawMinFee") );
        put( "percentage", false );
    }} );
    put( "deposit", new java.util.HashMap<String, Object>() {{
        put( "fee", null );
        put( "percentage", null );
    }} );
}});
            }
            return resultNew;
        }
        Object minWithdrawFee = this.safeNumber(fee, "withdrawMinFee");
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", fee );
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "fee", minWithdrawFee );
                put( "percentage", false );
            }} );
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "fee", null );
                put( "percentage", null );
            }} );
            put( "networks", new java.util.HashMap<String, Object>() {{}} );
        }};
        Object networkId = this.safeString(fee, "chain");
        Object networkCode = this.networkIdToCode(networkId, this.safeString(currency, "code"));
        Helpers.addElementToObject(Helpers.GetValue(result, "networks"), networkCode, new java.util.HashMap<String, Object>() {{
    put( "withdraw", minWithdrawFee );
    put( "deposit", new java.util.HashMap<String, Object>() {{
        put( "fee", null );
        put( "percentage", null );
    }} );
}});
        return result;
    }

    public Object isFuturesMethod(Object methodName, Object parameters)
    {
        //
        // Helper
        // @methodName (string): The name of the method
        // @params (dict): The parameters passed into {methodName}
        // @return: true if the method used is meant for futures trading, false otherwise
        //
        Object defaultType = this.safeString2(this.options, methodName, "defaultType", "trade");
        Object requestedType = this.safeString(parameters, "type", defaultType);
        Object accountsByType = this.safeDict(this.options, "accountsByType");
        Object type = this.safeString(accountsByType, requestedType);
        if (Helpers.isTrue(Helpers.isEqual(type, null)))
        {
            Object keys = new java.util.ArrayList<Object>(((java.util.Map<String, Object>)accountsByType).keySet());
            throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " isFuturesMethod() type must be one of "), String.join((String)", ", (java.util.List<String>)keys))) ;
        }
        parameters = this.omit(parameters, "type");
        return Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(type, "contract"))) || Helpers.isTrue((Helpers.isEqual(type, "future")))) || Helpers.isTrue((Helpers.isEqual(type, "futures")));  // * (type === 'futures') deprecated, use (type === 'future')
    }

    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol": "BTC-USDT",   // symbol
        //         "symbolName":"BTC-USDT", // Name of trading pairs, it would change after renaming
        //         "buy": "11328.9",   // bestAsk
        //         "sell": "11329",    // bestBid
        //         "changeRate": "-0.0055",    // 24h change rate
        //         "changePrice": "-63.6", // 24h change price
        //         "high": "11610",    // 24h highest price
        //         "low": "11200", // 24h lowest price
        //         "vol": "2282.70993217", // 24h volume，the aggregated trading volume in BTC
        //         "volValue": "25984946.157790431",   // 24h total, the trading volume in quote currency of last 24 hours
        //         "last": "11328.9",  // last price
        //         "averagePrice": "11360.66065903",   // 24h average transaction price yesterday
        //         "takerFeeRate": "0.001",    // Basic Taker Fee
        //         "makerFeeRate": "0.001",    // Basic Maker Fee
        //         "takerCoefficient": "1",    // Taker Fee Coefficient
        //         "makerCoefficient": "1" // Maker Fee Coefficient
        //     }
        //
        //     {
        //         "trading": true,
        //         "symbol": "KCS-BTC",
        //         "buy": 0.00011,
        //         "sell": 0.00012,
        //         "sort": 100,
        //         "volValue": 3.13851792584,   //total
        //         "baseCurrency": "KCS",
        //         "market": "BTC",
        //         "quoteCurrency": "BTC",
        //         "symbolCode": "KCS-BTC",
        //         "datetime": 1548388122031,
        //         "high": 0.00013,
        //         "vol": 27514.34842,
        //         "low": 0.0001,
        //         "changePrice": -1.0e-5,
        //         "changeRate": -0.0769,
        //         "lastTradedPrice": 0.00012,
        //         "board": 0,
        //         "mark": 0
        //     }
        //
        // market/ticker ws subscription
        //
        //     {
        //         "bestAsk": "62258.9",
        //         "bestAskSize": "0.38579986",
        //         "bestBid": "62258.8",
        //         "bestBidSize": "0.0078381",
        //         "price": "62260.7",
        //         "sequence": "1621383297064",
        //         "size": "0.00002841",
        //         "time": 1634641777363
        //     }
        //
        // uta
        //
        //     {
        //         "symbol": "BTC-USDT",
        //         "name": "BTC-USDT",
        //         "bestBidSize": "0.69207954",
        //         "bestBidPrice": "110417.5",
        //         "bestAskSize": "0.08836606",
        //         "bestAskPrice": "110417.6",
        //         "lastPrice": "110417.5",
        //         "size": "0.00016",
        //         "open": "110105.1",
        //         "high": "110838.9",
        //         "low": "109705.5",
        //         "baseVolume": "1882.10069442",
        //         "quoteVolume": "207325626.822922498"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object percentage = this.safeString(ticker, "changeRate");
        if (Helpers.isTrue(!Helpers.isEqual(percentage, null)))
        {
            percentage = Precise.stringMul(percentage, "100");
        }
        Object last = this.safeStringN(ticker, new java.util.ArrayList<Object>(java.util.Arrays.asList("last", "lastTradedPrice", "lastPrice")));
        last = this.safeString(ticker, "price", last);
        Object marketId = this.safeString(ticker, "symbol");
        market = this.safeMarket(marketId, market, "-");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object baseVolume = this.safeString2(ticker, "vol", "baseVolume");
        Object quoteVolume = this.safeString2(ticker, "volValue", "quoteVolume");
        Object timestamp = this.safeIntegerN(ticker, new java.util.ArrayList<Object>(java.util.Arrays.asList("time", "datetime", "timePoint")));
        final Object finalLast = last;
        final Object finalPercentage = percentage;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", Kucoin.this.iso8601(timestamp) );
            put( "high", Kucoin.this.safeString(ticker, "high") );
            put( "low", Kucoin.this.safeString(ticker, "low") );
            put( "bid", Kucoin.this.safeStringN(ticker, new java.util.ArrayList<Object>(java.util.Arrays.asList("buy", "bestBid", "bestBidPrice"))) );
            put( "bidVolume", Kucoin.this.safeString(ticker, "bestBidSize") );
            put( "ask", Kucoin.this.safeStringN(ticker, new java.util.ArrayList<Object>(java.util.Arrays.asList("sell", "bestAsk", "bestAskPrice"))) );
            put( "askVolume", Kucoin.this.safeString(ticker, "bestAskSize") );
            put( "vwap", null );
            put( "open", Kucoin.this.safeString(ticker, "open") );
            put( "close", finalLast );
            put( "last", finalLast );
            put( "previousClose", null );
            put( "change", Kucoin.this.safeString(ticker, "changePrice") );
            put( "percentage", finalPercentage );
            put( "average", Kucoin.this.safeString(ticker, "averagePrice") );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "markPrice", Kucoin.this.safeString(ticker, "value") );
            put( "info", ticker );
        }}, market);
    }

    /**
     * @method
     * @name kucoin#fetchTickers
     * @description fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for each market
     * @see https://docs.kucoin.com/#get-all-tickers
     * @see https://www.kucoin.com/docs-new/rest/ua/get-ticker
     * @param {string[]|undefined} symbols unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.uta] set to true for the unified trading account (uta), defaults to false
     * @param {string} [params.tradeType] *uta only* set to SPOT or FUTURES
     * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            symbols = this.marketSymbols(symbols);
            Object uta = null;
            var utaparametersVariable = this.handleOptionAndParams(parameters, "fetchTickers", "uta", false);
            uta = ((java.util.List<Object>) utaparametersVariable).get(0);
            parameters = ((java.util.List<Object>) utaparametersVariable).get(1);
            Object response = null;
            if (Helpers.isTrue(uta))
            {
                if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
                {
                    Object symbol = this.safeString(symbols, 0);
                    Object market = this.market(symbol);
                    Object type = null;
                    var typeparametersVariable = this.handleMarketTypeAndParams("fetchTickers", market, parameters);
                    type = ((java.util.List<Object>) typeparametersVariable).get(0);
                    parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
                    if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
                    {
                        Helpers.addElementToObject(request, "tradeType", "SPOT");
                    } else
                    {
                        Helpers.addElementToObject(request, "tradeType", "FUTURES");
                    }
                } else
                {
                    Object tradeType = this.safeStringUpper(parameters, "tradeType");
                    if (Helpers.isTrue(Helpers.isEqual(tradeType, null)))
                    {
                        throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchTickers() requires a tradeType parameter for uta, either SPOT or FUTURES")) ;
                    }
                    Helpers.addElementToObject(request, "tradeType", tradeType);
                    parameters = this.omit(parameters, "tradeType");
                }
                response = (this.utaGetMarketTicker(this.extend(request, parameters))).join();
            } else
            {
                response = (this.publicGetMarketAllTickers(parameters)).join();
            }
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object tickers = this.safeList2(data, "ticker", "list", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object time = this.safeInteger2(data, "time", "ts");
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(tickers)); i++)
            {
                Helpers.addElementToObject(Helpers.GetValue(tickers, i), "time", time);
                Object ticker = this.parseTicker(Helpers.GetValue(tickers, i));
                Object symbol = this.safeString(ticker, "symbol");
                if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
                {
                    Helpers.addElementToObject(result, symbol, ticker);
                }
            }
            return this.filterByArrayTickers(result, "symbol", symbols);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

