    /**
     * @method
     * @name kucoin#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://docs.kucoin.com/#get-klines
     * @see https://www.kucoin.com/docs-new/rest/ua/get-klines
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.uta] set to true for the unified trading account (uta), defaults to false
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchOHLCV", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDeterministic("fetchOHLCV", symbol, since, limit, timeframe, parameters, 1500)).join();
            }
            Object market = this.market(symbol);
            Object marketId = Helpers.GetValue(market, "id");
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", marketId );
            }};
            Object duration = Helpers.multiply(this.parseTimeframe(timeframe), 1000);
            Object endAt = this.milliseconds(); // required param
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "startAt", this.parseToInt((Math.floor(Double.parseDouble(Helpers.toString(Helpers.divide(since, 1000)))))));
                if (Helpers.isTrue(Helpers.isEqual(limit, null)))
                {
                    // https://docs.kucoin.com/#get-klines
                    // https://docs.kucoin.com/#details
                    // For each query, the system would return at most 1500 pieces of data.
                    // To obtain more data, please page the data by time.
                    limit = this.safeInteger(this.options, "fetchOHLCVLimit", 1500);
                }
                endAt = this.sum(since, Helpers.multiply(limit, duration));
            } else if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                since = Helpers.subtract(endAt, Helpers.multiply(limit, duration));
                Helpers.addElementToObject(request, "startAt", this.parseToInt((Math.floor(Double.parseDouble(Helpers.toString(Helpers.divide(since, 1000)))))));
            }
            Helpers.addElementToObject(request, "endAt", this.parseToInt((Math.floor(Double.parseDouble(Helpers.toString(Helpers.divide(endAt, 1000)))))));
            Object uta = null;
            var utaparametersVariable = this.handleOptionAndParams(parameters, "fetchOHLCV", "uta", false);
            uta = ((java.util.List<Object>) utaparametersVariable).get(0);
            parameters = ((java.util.List<Object>) utaparametersVariable).get(1);
            Object response = null;
            Object result = null;
            if (Helpers.isTrue(uta))
            {
                Object type = null;
                var typeparametersVariable = this.handleMarketTypeAndParams("fetchOHLCV", market, parameters);
                type = ((java.util.List<Object>) typeparametersVariable).get(0);
                parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
                if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
                {
                    Helpers.addElementToObject(request, "tradeType", "SPOT");
                } else
                {
                    Helpers.addElementToObject(request, "tradeType", "FUTURES");
                }
                Helpers.addElementToObject(request, "interval", this.safeString(this.timeframes, timeframe, timeframe));
                response = (this.utaGetMarketKline(this.extend(request, parameters))).join();
                //
                //     {
                //         "code": "200000",
                //         "data": {
                //             "tradeType": "SPOT",
                //             "symbol": "BTC-USDT",
                //             "list": [
                //                 ["1762240200","104581.4","104527.1","104620.1","104526.4","5.57665554","583263.661804122"],
                //                 ["1762240140","104565.6","104581.3","104601.7","104511.3","6.48505114","677973.775916968"],
                //                 ["1762240080","104621.5","104571.3","104704.7","104571.3","14.51713618","1519468.954060838"]
                //             ]
                //         }
                //     }
                //
                Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
                result = this.safeList(data, "list", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            } else
            {
                Helpers.addElementToObject(request, "type", this.safeString(this.timeframes, timeframe, timeframe));
                response = (this.publicGetMarketCandles(this.extend(request, parameters))).join();
                //
                //     {
                //         "code":"200000",
                //         "data":[
                //             ["1591517700","0.025078","0.025069","0.025084","0.025064","18.9883256","0.4761861079404"],
                //             ["1591516800","0.025089","0.025079","0.025089","0.02506","99.4716622","2.494143499081"],
                //             ["1591515900","0.025079","0.02509","0.025091","0.025068","59.83701271","1.50060885172798"],
                //         ]
                //     }
                //
                result = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            }
            return this.parseOHLCVs(result, market, timeframe, since, limit);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

