    public Object parseDepositAddress(Object depositAddress, Object... optionalArgs)
    {
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object address = this.safeString(depositAddress, "address");
        // BCH/BSV is returned with a "bitcoincash:" prefix, which we cut off here and only keep the address
        if (Helpers.isTrue(!Helpers.isEqual(address, null)))
        {
            address = Helpers.replace((String)address, (String)"bitcoincash:", (String)"");
        }
        Object code = null;
        if (Helpers.isTrue(!Helpers.isEqual(currency, null)))
        {
            code = this.safeCurrencyCode(Helpers.GetValue(currency, "id"));
            if (Helpers.isTrue(!Helpers.isEqual(code, "NIM")))
            {
                // contains spaces
                this.checkAddress(address);
            }
        }
        final Object finalCode = code;
        final Object finalAddress = address;
        return new java.util.HashMap<String, Object>() {{
            put( "info", depositAddress );
            put( "currency", finalCode );
            put( "network", Kucoin.this.networkIdToCode(Kucoin.this.safeString(depositAddress, "chainId")) );
            put( "address", finalAddress );
            put( "tag", Kucoin.this.safeString(depositAddress, "memo") );
        }};
    }

