    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object code = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchDeposits", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDynamic("fetchDeposits", code, since, limit, parameters)).join();
            }
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object currency = null;
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                currency = this.currency(code);
                Helpers.addElementToObject(request, "currency", Helpers.GetValue(currency, "id"));
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "pageSize", limit);
            }
            var requestparametersVariable = this.handleUntilOption("endAt", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(since, null)) && Helpers.isTrue(Helpers.isLessThan(since, 1550448000000L))))
            {
                // if since is earlier than 2019-02-18T00:00:00Z
                Helpers.addElementToObject(request, "startAt", this.parseToInt(Helpers.divide(since, 1000)));
                response = (this.privateGetHistDeposits(this.extend(request, parameters))).join();
            } else
            {
                if (Helpers.isTrue(!Helpers.isEqual(since, null)))
                {
                    Helpers.addElementToObject(request, "startAt", since);
                }
                response = (this.privateGetDeposits(this.extend(request, parameters))).join();
            }
            //
            //     {
            //         "code": "200000",
            //         "data": {
            //             "currentPage": 1,
            //             "pageSize": 5,
            //             "totalNum": 2,
            //             "totalPage": 1,
            //             "items": [
            //                 //--------------------------------------------------
            //                 // version 2 deposit response structure
            //                 {
            //                     "address": "0x5f047b29041bcfdbf0e4478cdfa753a336ba6989",
            //                     "memo": "5c247c8a03aa677cea2a251d",
            //                     "amount": 1,
            //                     "fee": 0.0001,
            //                     "currency": "KCS",
            //                     "isInner": false,
            //                     "walletTxId": "5bbb57386d99522d9f954c5a@test004",
            //                     "status": "SUCCESS",
            //                     "createdAt": 1544178843000,
            //                     "updatedAt": 1544178891000
            //                     "remark":"foobar"
            //                 },
            //                 //--------------------------------------------------
            //                 // version 1 (historical) deposit response structure
            //                 {
            //                     "currency": "BTC",
            //                     "createAt": 1528536998,
            //                     "amount": "0.03266638",
            //                     "walletTxId": "55c643bc2c68d6f17266383ac1be9e454038864b929ae7cee0bc408cc5c869e8@12ffGWmMMD1zA1WbFm7Ho3JZ1w6NYXjpFk@234",
            //                     "isInner": false,
            //                     "status": "SUCCESS",
            //                 }
            //             ]
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object items = this.safeList(data, "items", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseTransactions(items, currency, since, limit, new java.util.HashMap<String, Object>() {{
                put( "type", "deposit" );
            }});
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

