    public Object parseBorrowInterest(Object info, Object... optionalArgs)
    {
        //
        // Cross
        //
        //     {
        //         "currency": "1INCH",
        //         "total": "0",
        //         "available": "0",
        //         "hold": "0",
        //         "liability": "0",
        //         "maxBorrowSize": "0",
        //         "borrowEnabled": true,
        //         "transferInEnabled": true
        //     }
        //
        // Isolated
        //
        //     {
        //         "symbol": "MANA-USDT",
        //         "debtRatio": "0",
        //         "status": "BORROW",
        //         "baseAsset": {
        //             "currency": "MANA",
        //             "borrowEnabled": true,
        //             "repayEnabled": true,
        //             "transferEnabled": true,
        //             "borrowed": "0",
        //             "totalAsset": "0",
        //             "available": "0",
        //             "hold": "0",
        //             "maxBorrowSize": "1000"
        //         },
        //         "quoteAsset": {
        //             "currency": "USDT",
        //             "borrowEnabled": true,
        //             "repayEnabled": true,
        //             "transferEnabled": true,
        //             "borrowed": "0",
        //             "totalAsset": "0",
        //             "available": "0",
        //             "hold": "0",
        //             "maxBorrowSize": "50000"
        //         }
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(info, "symbol");
        Object marginMode = ((Helpers.isTrue((Helpers.isEqual(marketId, null))))) ? "cross" : "isolated";
        market = this.safeMarket(marketId, market);
        Object symbol = this.safeString(market, "symbol");
        Object timestamp = this.safeInteger(info, "createdAt");
        Object isolatedBase = this.safeDict(info, "baseAsset", new java.util.HashMap<String, Object>() {{}});
        Object amountBorrowed = null;
        Object interest = null;
        Object currencyId = null;
        if (Helpers.isTrue(Helpers.isEqual(marginMode, "isolated")))
        {
            amountBorrowed = this.safeNumber(isolatedBase, "liability");
            interest = this.safeNumber(isolatedBase, "interest");
            currencyId = this.safeString(isolatedBase, "currency");
        } else
        {
            amountBorrowed = this.safeNumber(info, "liability");
            interest = this.safeNumber(info, "accruedInterest");
            currencyId = this.safeString(info, "currency");
        }
        final Object finalCurrencyId = currencyId;
        final Object finalInterest = interest;
        final Object finalAmountBorrowed = amountBorrowed;
        final Object finalMarginMode = marginMode;
        return new java.util.HashMap<String, Object>() {{
            put( "info", info );
            put( "symbol", symbol );
            put( "currency", Kucoin.this.safeCurrencyCode(finalCurrencyId) );
            put( "interest", finalInterest );
            put( "interestRate", Kucoin.this.safeNumber(info, "dailyIntRate") );
            put( "amountBorrowed", finalAmountBorrowed );
            put( "marginMode", finalMarginMode );
            put( "timestamp", timestamp );
            put( "datetime", Kucoin.this.iso8601(timestamp) );
        }};
    }

